<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Facades\Http;

class LinkPreviewController extends Controller
{
    public function show(Request $request)
    {
        $url = $request->input('url');

        if (!$url) {
            return response()->json(['error' => 'URL is required'], 422);
        }

        $response = Http::timeout(10)->get($url);

        if (!$response->successful()) {
            return response()->json(['error' => 'Unable to fetch URL'], 400);
        }

        $html = $response->body();

        preg_match('/<title[^>]*>(.*?)<\/title>/is', $html, $titleMatch);
        preg_match('/<meta[^>]+name=["\']description["\'][^>]+content=["\'](.*?)["\']/is', $html, $descriptionMatch);
        preg_match('/<meta[^>]+property=["\']og:image["\'][^>]+content=["\'](.*?)["\']/is', $html, $imageMatch);

        return response()->json([
            'url' => $url,
            'title' => $titleMatch[1] ?? null,
            'description' => $descriptionMatch[1] ?? null,
            'image' => $imageMatch[1] ?? null,
        ]);
    }
}